namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 4;
    private readonly List<Notification> _notifications =
    [
        new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)),
        new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)),
        new(3, "New feature available: Dark Mode.", DateTime.UtcNow.AddMinutes(-1)),
    ];

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(int lastId)
    {
        lock (_notifications)
        {
            // Simulate new notifications appearing over time
            if (Random.Shared.NextDouble() > 0.6)
            {
                var id = _nextId++;
                _notifications.Add(new Notification(id, $"New event #{id} occurred.", DateTime.UtcNow));
            }

            var newer = _notifications.Where(n => n.Id > lastId).ToList();
            return Task.FromResult(newer);
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@notifications.Count</span></h1>

@if (notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item">
                <strong>@n.Message</strong>
                <small class="text-muted ms-2">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification> notifications { get; set; } = [];

    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if not restored from prerender state
        if (notifications.Count == 0)
        {
            notifications = await NotificationService.GetNotificationsAsync();
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Start polling only after the page is interactive (never during prerender)
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var lastId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
                var newer = await NotificationService.GetNotificationsSinceAsync(lastId);

                if (newer.Count > 0)
                {
                    notifications.AddRange(newer);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

